import React, {Component} from 'react'

export class Categories extends Component {
    constructor(props) {
        super(props)
        {
            this.state = {
                categories:[
                    {
                        key:'all',
                        name:'Усі'
                    },
                    {
                        key:'chairs',
                        name:'Стільці'
                    },
                    {
                        key:'tables',
                        name:'Столи'
                    },
                    {
                        key:'sofa',
                        name:'Ліжко'
                    },
                    {
                        key:'wardrobe',
                        name:'Шафа'
                    },
                ]
            }
        }
    }

    render() {
        return (
            <div className='categories'>
                {this.state.categories.map(el =>(
                    <div key={el.key}>{el.name}</div>
                ))}
            </div>
        )
    }
}


export default Categories;
